parameters.jsCode:
const items = $input.all();
const outputItems = [];

items.forEach(item => {
  const jobRole = item.json.JobRole || '';

  // Auto-generate FormDate (submission date)
  const formDate = new Date();
  const formDateStr = formDate.toISOString().split('T')[0];

  // Auto-generate Joining Date → 1st of next month
  const nextMonth = new Date(formDate.getFullYear(), formDate.getMonth() + 1, 1);
  const joiningDateStr = nextMonth.toISOString().split('T')[0];

  if (item.binary) {
    if (item.binary.Aadhar) {
      outputItems.push({
        json: {
          ...item.json,
          documentType: 'Aadhar',
          JobRole: jobRole,
          FormDate: formDateStr,
          JoiningDate: joiningDateStr,

        },
        binary: { Document: item.binary.Aadhar }
      });
    }

    if (item.binary.Resume) {
      outputItems.push({
        json: {
          ...item.json,
          documentType: 'Resume',
          JobRole: jobRole,
          FormDate: formDateStr,
          JoiningDate: joiningDateStr,

        },
        binary: { Document: item.binary.Resume }
      });
    }
  }
});

return outputItems;
